  const wasmModulePath = require.resolve("@prisma/client/runtime/query_compiler_bg.postgresql.wasm")
  const wasmModuleBytes = await readFile(wasmModulePath)

  return new globalThis.WebAssembly.Module(wasmModuleBytes)
}
