index 66a5f2857b8019ad8d5e019e9ef2879da45264b3..276a008893de13a1d0552eb9dcf49a860738fb8f 100644
--- a/lib/Compilation.js
+++ b/lib/Compilation.js
@@ -2884,6 +2884,28 @@
 		 * @param {Module} module module
 		 * @returns {References} references
 		 */
+		/**
+		 * https://github.com/webpack/webpack/issues/20800 ŌĆö for asset modules,
+		 * the set of source types returned by AssetGenerator.getTypes() depends
+		 * on the *types* of the incoming connection origin modules (CSS vs JS).
+		 * Track that signature so memCache2 is invalidated when a previously
+		 * CSS-only asset becomes JS-referenced (e.g. via a newly-activated
+		 * lazy entry). Without this, the hash recomputation in
+		 * NormalModule.updateHash never fires and the JS code factory for the
+		 * asset is missing from the new chunk at runtime.
+		 * @param {Module} module module
+		 * @returns {Set<string> | undefined} origin source-type signature, or undefined for non-asset modules
+		 */
+		const computeAssetOriginTypes = (module) => {
+			if (!module.type || !module.type.startsWith("asset/")) return undefined;
+			const result = new Set();
+			for (const connection of moduleGraph.getIncomingConnections(module)) {
+				if (connection.originModule) {
+					result.add(connection.originModule.type.split("/")[0]);
+				}
+			}
+			return result;
+		};
 		const computeReferences = (module) => {
 			const id = /** @type {ModuleId} */ (chunkGraph.getModuleId(module));
 			/** @type {Map<Module, ModuleId> | undefined} */
@@ -2914,7 +2936,8 @@
 					queue.push.apply(queue, block.blocks);
 				}
 			}
-			return { id, modules, blocks };
+			const assetOriginTypes = computeAssetOriginTypes(module);
+			return { id, modules, blocks, assetOriginTypes };
 		};
 		/**
 		 * Compares references.
@@ -2925,7 +2948,7 @@
 		 * @param {(string | number | null)[]=} references.blocks blocks
 		 * @returns {boolean} ok?
 		 */
-		const compareReferences = (module, { id, modules, blocks }) => {
+		const compareReferences = (module, { id, modules, blocks, assetOriginTypes }) => {
 			if (id !== chunkGraph.getModuleId(module)) return false;
 			if (modules !== undefined) {
 				for (const [module, id] of modules) {
@@ -2949,6 +2972,13 @@
